33	}
34	
35	/* We do need to come up with an effective way to see what is already in the
36	 * file to avoid adding to what is already there. This is avoided for pdfwrite
37	 * as we check as we add each font. For adding text to an existing file though
38	 * it may be more problematic. */
39	
40	pdf_obj *
41	pdf_find_font_resource(fz_context *ctx, pdf_document *doc, int type, int encoding, fz_font *item, pdf_font_resource_key *key)
42	{
43		pdf_obj *res;
44	
45		if (!doc->resources.fonts)
46			doc->resources.fonts = fz_new_hash_table(ctx, 4096, sizeof(*key), -1, pdf_drop_obj_as_void);
47	
48		memset(key, 0, sizeof(*key));
49		fz_font_digest(ctx, item, key->digest);
50	
51		key->type = type;
52		key->encoding = encoding;
53		key->local_xref = doc->local_xref_nesting > 0;
54	
55		res = fz_hash_find(ctx, doc->resources.fonts, (void *)key);
56		if (res)
57			pdf_keep_obj(ctx, res);
58		return res;
59	}
60	
61	pdf_obj *
62	pdf_find_colorspace_resource(fz_context *ctx, pdf_document *doc, fz_colorspace *item, pdf_colorspace_resource_key *key)
63	{
64		pdf_obj *res;
65	
66		if (!doc->resources.colorspaces)
67			doc->resources.colorspaces = fz_new_hash_table(ctx, 4096, sizeof(*key), -1, pdf_drop_obj_as_void);
68	
69		memset(key, 0, sizeof(*key));
70		fz_colorspace_digest(ctx, item, key->digest);
71	
72		key->local_xref = doc->local_xref_nesting > 0;
73	
74		res = fz_hash_find(ctx, doc->resources.colorspaces, (void *)key);
75		if (res)
76			pdf_keep_obj(ctx, res);
77		return res;
78	}
79	
80	pdf_obj *
81	pdf_find_image_resource(fz_context *ctx, pdf_document *doc, fz_image *item, pdf_image_resource_key *key)
82	{
83		pdf_obj *res;
84	
85		if (!doc->resources.images)
86			doc->resources.images = fz_new_hash_table(ctx, 4096, sizeof(*key), -1, pdf_drop_obj_as_void);
87	
88		memset(key, 0, sizeof(*key));
89	
90		key->w = item->w;
91		key->h = item->h;
92		key->n = item->n;
93		key->bpc = item->bpc;
94		key->imagemask = item->imagemask;
95		key->use_colorkey = item->use_colorkey;
96		key->use_decode = item->use_decode;
97		key->decode = crc32(0, (unsigned char *)item->decode, 2 * item->n * sizeof(float));
98		key->decode = crc32(key->decode, (unsigned char *)item->colorkey, 2 * item->n * sizeof(int));
99	
100		if (item->mask)
101			fz_image_digest(ctx, item->mask, key->mask);
102	
103		fz_image_digest(ctx, item, key->digest);
104	
105		key->local_xref = doc->local_xref_nesting > 0;
106	
107		res = fz_hash_find(ctx, doc->resources.images, (void *)key);
108		if (res)
109			pdf_keep_obj(ctx, res);
110		return res;
111	}
112	
113	pdf_obj *
114	pdf_insert_font_resource(fz_context *ctx, pdf_document *doc, pdf_font_resource_key *key, pdf_obj *obj)
115	{
116		pdf_obj *res = fz_hash_insert(ctx, doc->resources.fonts, (void *)key, obj);
117		if (res)
118			fz_warn(ctx, "warning: font resource already present");
119		else
120			res = pdf_keep_obj(ctx, obj);
121		return pdf_keep_obj(ctx, res);
122	}
123	
124	pdf_obj *
125	pdf_insert_colorspace_resource(fz_context *ctx, pdf_document *doc, pdf_colorspace_resource_key *key, pdf_obj *obj)
126	{
127		pdf_obj *res = fz_hash_insert(ctx, doc->resources.colorspaces, (void *)key, obj);
128		if (res)
129			fz_warn(ctx, "warning: colorspace resource already present");
130		else
131			res = pdf_keep_obj(ctx, obj);
132		return pdf_keep_obj(ctx, res);
133	}
134	
135	pdf_obj *
136	pdf_insert_image_resource(fz_context *ctx, pdf_document *doc, pdf_image_resource_key *key, pdf_obj *obj)
137	{
138		pdf_obj *res = fz_hash_insert(ctx, doc->resources.images, (void *)key, obj);
139		if (res)
140			fz_warn(ctx, "warning: image resource already present");
141		else
142			res = pdf_keep_obj(ctx, obj);
143		return pdf_keep_obj(ctx, res);
144	}
