146	static int purge_local_font_resource(fz_context *ctx, void *state, void *key_, int keylen, void *val)
147	{
148		pdf_font_resource_key *key = key_;
149		if (key->local_xref)
150		{
151			pdf_drop_obj(ctx, val);
152			return 1;
153		}
154		return 0;
155	}
