157	static int purge_local_colorspace_resource(fz_context *ctx, void *state, void *key_, int keylen, void *val)
158	{
159		pdf_colorspace_resource_key *key = key_;
160		if (key->local_xref)
161		{
162			pdf_drop_obj(ctx, val);
163			return 1;
164		}
165		return 0;
166	}
