168	static int purge_local_image_resource(fz_context *ctx, void *state, void *key_, int keylen, void *val)
169	{
170		pdf_image_resource_key *key = key_;
171		if (key->local_xref)
172		{
173			pdf_drop_obj(ctx, val);
174			return 1;
175		}
176		return 0;
177	}
178	
179	void
180	pdf_purge_local_resources(fz_context *ctx, pdf_document *doc)
181	{
182		if (doc->resources.fonts)
183			fz_hash_filter(ctx, doc->resources.fonts, NULL, purge_local_font_resource);
184		if (doc->resources.colorspaces)
185			fz_hash_filter(ctx, doc->resources.colorspaces, NULL, purge_local_colorspace_resource);
186		if (doc->resources.images)
187			fz_hash_filter(ctx, doc->resources.images, NULL, purge_local_image_resource);
188	}
189	
190	void
191	pdf_drop_resource_tables(fz_context *ctx, pdf_document *doc)
192	{
193		if (doc)
194		{
195			fz_drop_hash_table(ctx, doc->resources.colorspaces);
196			fz_drop_hash_table(ctx, doc->resources.fonts);
197			fz_drop_hash_table(ctx, doc->resources.images);
198		}
199	}
