422	pdf_processor *pdf_new_vectorize_filter(fz_context *ctx, pdf_document *doc, pdf_processor *chain, int structparents, fz_matrix transform, pdf_filter_options *options, void *vopts);
423	
424	pdf_obj *pdf_filter_xobject_instance(fz_context *ctx, pdf_obj *old_xobj, pdf_obj *page_res, fz_matrix ctm, pdf_filter_options *options, pdf_cycle_list *cycle_up);
425	
426	void pdf_processor_push_resources(fz_context *ctx, pdf_processor *proc, pdf_obj *res);
427	
428	pdf_obj *pdf_processor_pop_resources(fz_context *ctx, pdf_processor *proc);
429	
430	/*
431		opaque: Opaque value that is passed to all the filter functions.
432	
433		color_rewrite: function pointer called to rewrite a color
434			On entry:
435				*cs = reference to a pdf object representing the colorspace.
436	
437				*n = number of color components
438	
439				color = *n color values.
440	
441			On exit:
442				*cs either the same (for no change in colorspace) or
443				updated to be a new one. Reference must be dropped, and
444				a new kept reference returned!
445	
446				*n = number of color components (maybe updated)
447	
448				color = *n color values (maybe updated)
449	
450		image_rewrite: function pointer called to rewrite an image
451			On entry:
452				*image = reference to an fz_image.
453	
454			On exit:
455				*image either the same (for no change) or updated
456				to be a new one. Reference must be dropped, and a
457				new kept reference returned.
458	
459		share_rewrite: function pointer called to rewrite a shade
460	
461		repeated_image_rewrite: If 0, then each image is rewritten only once.
462			Otherwise, it is called for every instance (useful if gathering
463			information about the ctm).
464	*/
465	typedef struct
466	{
467		void *opaque;
468		void (*color_rewrite)(fz_context *ctx, void *opaque, pdf_obj **cs, int *n, float color[FZ_MAX_COLORS]);
469		void (*image_rewrite)(fz_context *ctx, void *opaque, fz_image **image, fz_matrix ctm, pdf_obj *obj);
470		pdf_shade_recolorer *shade_rewrite;
471		int repeated_image_rewrite;
472	} pdf_color_filter_options;
473	
474	pdf_processor *
475	pdf_new_color_filter(fz_context *ctx, pdf_document *doc, pdf_processor *chain, int struct_parents, fz_matrix transform, pdf_filter_options *options, void *copts);
476	
477	/*
478		Functions to actually process annotations, glyphs and general stream objects.
479	*/
480	void pdf_process_contents(fz_context *ctx, pdf_processor *proc, pdf_document *doc, pdf_obj *res, pdf_obj *stm, fz_cookie *cookie, pdf_obj **out_res);
481	void pdf_process_annot(fz_context *ctx, pdf_processor *proc, pdf_annot *annot, fz_cookie *cookie);
482	void pdf_process_glyph(fz_context *ctx, pdf_processor *proc, pdf_document *doc, pdf_obj *resources, fz_buffer *contents);
483	
484	/*
485		Function to process a contents stream without handling the resources.
486		The caller is responsible for pushing/popping the resources.
487	*/
488	void pdf_process_raw_contents(fz_context *ctx, pdf_processor *proc, pdf_document *doc, pdf_obj *stmobj, fz_cookie *cookie);
489	
490	/* Text handling helper functions */
491	typedef struct
492	{
493		float char_space;
494		float word_space;
495		float scale;
496		float leading;
497		pdf_font_desc *font;
498		fz_string *fontname;
499		float size;
500		int render;
501		float rise;
502	} pdf_text_state;
503	
504	typedef struct
505	{
506		fz_text *clip_text; /* accumulator for clip mode text */
507		fz_text *text;
508		fz_rect text_bbox;
509		fz_matrix tlm;
510		fz_matrix tm;
511		int text_mode;
512	
513		int cid;
514		int gid;
515		fz_rect char_bbox;
516		pdf_font_desc *fontdesc;
517		float char_tx;
518		float char_ty;
519	} pdf_text_object_state;
520	
521	void pdf_tos_save(fz_context *ctx, pdf_text_object_state *tos, fz_matrix save[2]);
522	void pdf_tos_restore(fz_context *ctx, pdf_text_object_state *tos, fz_matrix save[2]);
523	fz_text *pdf_tos_get_text(fz_context *ctx, pdf_text_object_state *tos);
524	fz_text *pdf_tos_get_clip_text(fz_context *ctx, pdf_text_object_state *tos);
525	void pdf_tos_reset(fz_context *ctx, pdf_text_object_state *tos, int render);
526	void pdf_tos_accumulate_clip(fz_context *ctx, pdf_text_object_state *tos);
527	int pdf_tos_make_trm(fz_context *ctx, pdf_text_object_state *tos, pdf_text_state *text, pdf_font_desc *fontdesc, int cid, fz_matrix *trm, float *adv);
528	void pdf_tos_move_after_char(fz_context *ctx, pdf_text_object_state *tos);
529	void pdf_tos_translate(pdf_text_object_state *tos, float tx, float ty);
530	void pdf_tos_set_matrix(pdf_text_object_state *tos, float a, float b, float c, float d, float e, float f);
531	void pdf_tos_newline(pdf_text_object_state *tos, float leading);
532	
533	#endif
